interface Sayable {
    String say();
}

public class LambdaBasic {
    public static void main(String[] args) {
        Sayable s = () -> "Hello, Lambda!";
        System.out.println(s.say());
    }
}

interface MathOperation {
    int operate(int a, int b);
}

public class LambdaIntermediate {
    public static void main(String[] args) {
        MathOperation addition = (a, b) -> {
            System.out.println("Adding " + a + " and " + b);
            return a + b;
        };
        System.out.println("Result: " + addition.operate(10, 20));
    }
}

import java.util.Arrays;
import java.util.List;

public class LambdaAdvanced {
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Alice", "Bob", "Charlie", "David");

        // Using lambda to filter and print names starting with 'C'
        names.stream()
             .filter(name -> name.startsWith("C"))
             .forEach(name -> System.out.println(name));
    }
}

